SELECT film.*, area.title as areaName, CONCAT(actor.id, ':', actor.actor) as actorInfo FROM film LEFT JOIN area ON film.area_id = area.id LEFT JOIN actor ON film.actor_id = actor.id
AND film.title LIKE CONCAT('%', #{title}, '%') AND film.type_ids LIKE CONCAT('%', #{typeId}, '%') AND film.start LIKE CONCAT('%', #{year}, '%') AND film.area_id = #{areaId} AND film.actor_id = #{actorId}
ORDER BY id DESC

